    #[derive(Clone, Debug, Eq, PartialEq)]
    struct SentMessageRecord {
        contact_id: ContactId,
        message_number: u64,
        message_type: MessageType,
        plaintext: Vec<u8>,
        created_at_ms: u128,
        ttl_seconds: u64,
        delivery_state: OutboundDeliveryState,
        failure_kind: Option<String>,
    }

    #[derive(Clone, Copy, Debug, Eq, PartialEq)]
    enum OutboundDeliveryState {
        Pending,
        Sent,
        Failed,
        Canceled,
    }

    impl OutboundDeliveryState {
        fn tag(self) -> &'static str {
            match self {
                Self::Pending => "pending",
                Self::Sent => "sent",
                Self::Failed => "failed",
                Self::Canceled => "canceled",
            }
        }

        fn parse(value: &str) -> Result<Self, ProductionSessionError> {
            match value {
                "pending" => Ok(Self::Pending),
                "sent" => Ok(Self::Sent),
                "failed" => Ok(Self::Failed),
                "canceled" => Ok(Self::Canceled),
                _ => Err(ProductionSessionError::UnexpectedEnvelope),
            }
        }

        fn retryable(self) -> bool {
            matches!(self, Self::Pending | Self::Failed)
        }
    }

    impl SentMessageRecord {
        fn new(
            contact_id: ContactId,
            message_number: u64,
            message_type: MessageType,
            plaintext: &[u8],
        ) -> Result<Self, ProductionSessionError> {
            Self::new_with_retention(contact_id, message_number, message_type, plaintext, 0, 0)
        }

        fn new_with_retention(
            contact_id: ContactId,
            message_number: u64,
            message_type: MessageType,
            plaintext: &[u8],
            created_at_ms: u128,
            ttl_seconds: u64,
        ) -> Result<Self, ProductionSessionError> {
            if message_number == 0 || plaintext.is_empty() {
                return Err(ProductionSessionError::UnexpectedEnvelope);
            }
            if (created_at_ms == 0) != (ttl_seconds == 0) {
                return Err(ProductionSessionError::UnexpectedEnvelope);
            }
            Ok(Self {
                contact_id,
                message_number,
                message_type,
                plaintext: plaintext.to_vec(),
                created_at_ms,
                ttl_seconds,
                delivery_state: OutboundDeliveryState::Pending,
                failure_kind: None,
            })
        }

        fn with_delivery_state(
            mut self,
            delivery_state: OutboundDeliveryState,
            failure_kind: Option<String>,
        ) -> Self {
            self.delivery_state = delivery_state;
            self.failure_kind = failure_kind
                .map(|kind| sanitize_outbound_failure_kind(&kind))
                .filter(|kind| !kind.is_empty());
            self
        }

        fn encode(&self) -> String {
            if self.delivery_state == OutboundDeliveryState::Pending
                && self.failure_kind.is_none()
                && self.created_at_ms == 0
                && self.ttl_seconds == 0
            {
                format!(
                    "ADSENTMSG1|{}|{}|{}|{}",
                    self.contact_id.as_str(),
                    self.message_number,
                    message_type_tag(&self.message_type),
                    encode_hex(&self.plaintext)
                )
            } else if self.delivery_state == OutboundDeliveryState::Pending
                && self.failure_kind.is_none()
            {
                format!(
                    "ADSENTMSG2|{}|{}|{}|{}|{}|{}",
                    self.contact_id.as_str(),
                    self.message_number,
                    message_type_tag(&self.message_type),
                    self.created_at_ms,
                    self.ttl_seconds,
                    encode_hex(&self.plaintext)
                )
            } else {
                format!(
                    "ADSENTMSG3|{}|{}|{}|{}|{}|{}|{}|{}",
                    self.contact_id.as_str(),
                    self.message_number,
                    message_type_tag(&self.message_type),
                    self.created_at_ms,
                    self.ttl_seconds,
                    encode_hex(&self.plaintext),
                    self.delivery_state.tag(),
                    self.failure_kind.as_deref().unwrap_or("none")
                )
            }
        }

        fn decode(value: &str) -> Result<Self, ProductionSessionError> {
            let parts = value.split('|').collect::<Vec<_>>();
            match parts.first().copied() {
                Some("ADSENTMSG1") if parts.len() == 5 => {
                    let contact_id = ContactId::new(parts[1])
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let message_number = parts[2]
                        .parse::<u64>()
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let message_type = parse_message_type_tag(parts[3])?;
                    let plaintext = decode_hex(parts[4])
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    Self::new(contact_id, message_number, message_type, &plaintext)
                }
                Some("ADSENTMSG2") if parts.len() == 7 => {
                    let contact_id = ContactId::new(parts[1])
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let message_number = parts[2]
                        .parse::<u64>()
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let message_type = parse_message_type_tag(parts[3])?;
                    let created_at_ms = parts[4]
                        .parse::<u128>()
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let ttl_seconds = parts[5]
                        .parse::<u64>()
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let plaintext = decode_hex(parts[6])
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    Self::new_with_retention(
                        contact_id,
                        message_number,
                        message_type,
                        &plaintext,
                        created_at_ms,
                        ttl_seconds,
                    )
                }
                Some("ADSENTMSG3") if parts.len() == 9 => {
                    let contact_id = ContactId::new(parts[1])
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let message_number = parts[2]
                        .parse::<u64>()
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let message_type = parse_message_type_tag(parts[3])?;
                    let created_at_ms = parts[4]
                        .parse::<u128>()
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let ttl_seconds = parts[5]
                        .parse::<u64>()
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let plaintext = decode_hex(parts[6])
                        .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                    let delivery_state = OutboundDeliveryState::parse(parts[7])?;
                    let failure_kind = match parts[8] {
                        "none" => None,
                        value => Some(sanitize_outbound_failure_kind(value)),
                    };
                    Ok(Self::new_with_retention(
                        contact_id,
                        message_number,
                        message_type,
                        &plaintext,
                        created_at_ms,
                        ttl_seconds,
                    )?
                    .with_delivery_state(delivery_state, failure_kind))
                }
                _ => Err(ProductionSessionError::UnexpectedEnvelope),
            }
        }

        fn expires_at_ms(&self) -> Option<u128> {
            if self.created_at_ms == 0 || self.ttl_seconds == 0 {
                None
            } else {
                Some(
                    self.created_at_ms
                        .saturating_add(u128::from(self.ttl_seconds).saturating_mul(1000)),
                )
            }
        }

        fn is_expired_at(&self, observed_at_ms: u128) -> bool {
            self.expires_at_ms()
                .map(|expires_at_ms| observed_at_ms >= expires_at_ms)
                .unwrap_or(false)
        }
    }

