    pub fn production_endpoint_update_control_envelope_export(
        store_path: impl AsRef<std::path::Path>,
        profile: ProfileName,
        passphrase: &ProfilePassphrase,
        message_number: u64,
        local_rendezvous_endpoint: impl Into<String>,
    ) -> Result<ProductionEndpointUpdateControlEnvelopeExportSummary, ProductionSessionError> {
        if message_number == 0 {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let locked = LockedProfileStore::new(store_path.as_ref());
        let store = locked.unlock(passphrase)?;
        if !store.profile_marker_exists(&profile)? {
            return Err(ProductionSessionError::ProfileMarkerMissing);
        }
        let material = load_session_runtime_material(&store, &profile)?;
        let draft = load_latest_session_draft(&store, &profile)?
            .ok_or(ProductionSessionError::SessionDraftMissing)?;
        let local_noise_static = store
            .get(&production_latest_pairing_noise_static_record_id())?
            .map(decode_production_noise_static_private_key_record)
            .transpose()?
            .ok_or(ProductionSessionError::NoiseStaticPrivateKeyMissing)?;
        if local_noise_static.keypair.public_key() != draft.local_noise_static_public_key {
            return Err(ProductionSessionError::NoiseStaticKeyMismatch);
        }
        let transport_state = load_session_transport_state(&store, &profile, &draft)?
            .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
        let session_transport_ready = transport_state.channel_id == material.channel_id
            && transport_state.local_role == draft.local_role
            && transport_state.remote_contact_id == material.remote_contact_id
            && transport_state.remote_noise_static_public_key
                == draft.remote_noise_static_public_key
            && transport_state.transport_state_created
            && matches!(
                (
                    draft.local_role,
                    transport_state.handshake_message_kind.as_str()
                ),
                (SessionRole::CanonicalDialer, "reply") | (SessionRole::Responder, "finish")
            );
        if !session_transport_ready {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let new_endpoint = OnionServiceEndpoint::new(local_rendezvous_endpoint.into())
            .map_err(|_| ProductionSessionError::InvalidRendezvousEndpoint)?;
        let update = PairwiseEndpointUpdate::for_existing_encrypted_session(
            &material.remote_endpoint,
            new_endpoint,
            EndpointUpdateChannel::ExistingEncryptedSession,
        )?;
        let plaintext = EndpointUpdateControlPlaintext::from_pairwise_update(&update);
        let padded = plaintext.encode_padded()?;
        let ciphertext = match draft.local_role {
            SessionRole::CanonicalDialer => {
                let state = store
                    .get(&production_pending_handshake_initiator_state_record_id())?
                    .map(|record| {
                        decode_production_handshake_initiator_state_record(
                            record,
                            &profile,
                            &draft.channel_id,
                        )
                    })
                    .transpose()?
                    .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
                let transport = create_noise_xx_stateless_initiator_transport(
                    &draft.safety_transcript,
                    &local_noise_static.keypair,
                    &state.initiator_ephemeral_private,
                    &transport_state.handshake_message,
                )
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                if transport.remote_static() != draft.remote_noise_static_public_key {
                    return Err(ProductionSessionError::NoiseStaticKeyMismatch);
                }
                transport
                    .encrypt_with_nonce(
                        production_message_transport_nonce(message_number, &MessageType::Control)?,
                        &padded,
                    )
                    .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?
            }
            SessionRole::Responder => {
                let state = store
                    .get(&production_pending_handshake_initiator_state_record_id())?
                    .map(|record| {
                        decode_production_handshake_responder_state_record(
                            record,
                            &profile,
                            &draft.channel_id,
                        )
                    })
                    .transpose()?
                    .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
                let transport = create_noise_xx_stateless_responder_transport(
                    &draft.safety_transcript,
                    &local_noise_static.keypair,
                    &state.init_message,
                    &state.responder_ephemeral_private,
                    &transport_state.handshake_message,
                )
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                if transport.remote_static() != draft.remote_noise_static_public_key {
                    return Err(ProductionSessionError::NoiseStaticKeyMismatch);
                }
                transport
                    .encrypt_with_nonce(
                        production_message_transport_nonce(message_number, &MessageType::Control)?,
                        &padded,
                    )
                    .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?
            }
        };
        if ciphertext.remote_static != draft.remote_noise_static_public_key
            || ciphertext.key_material_exposed
        {
            return Err(ProductionSessionError::NoiseStaticKeyMismatch);
        }
        let control = EncryptedEndpointUpdateControlEnvelope::from_pairwise_update(
            &update,
            material.channel_id.clone(),
            message_number,
            ciphertext.ciphertext,
        )?;
        let envelope = control.envelope().clone();
        let message_record_id = production_message_envelope_record_id(
            &material.channel_id,
            message_number,
            MessageType::Control,
        );
        if store.get(&message_record_id)?.is_some() {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let envelope_record = EncryptedRecord::new(
            ProductionRecordKind::MessageEnvelope,
            EncryptedRecordScope::contact(profile, material.remote_contact_id),
            b"sqlcipher-page-encryption-v1".to_vec(),
            envelope.encode().into_bytes(),
        )
        .map_err(ProductionStorageError::from)?;
        store.put(&message_record_id, &envelope_record)?;
        Ok(ProductionEndpointUpdateControlEnvelopeExportSummary {
            storage_opened: true,
            runtime_material_reconstructable: true,
            session_transport_ready,
            endpoint_update_created: true,
            encrypted_control_envelope_written: true,
            envelope_decodable: true,
            envelope_message_number_matches: envelope.message_number == message_number,
            envelope_message_type_control: envelope.message_type == MessageType::Control,
            export_payload: format!("{}\n", envelope.encode()),
            endpoint_plaintext_exposed: false,
            network_send_attempted: false,
            key_material_exposed: false,
            transport_io_opened: false,
            runtime_messaging_enabled: false,
        })
    }

    pub fn production_endpoint_update_control_envelope_import(
        store_path: impl AsRef<std::path::Path>,
        profile: ProfileName,
        passphrase: &ProfilePassphrase,
        envelope_payload: &str,
    ) -> Result<ProductionEndpointUpdateControlEnvelopeImportSummary, ProductionSessionError> {
        let locked = LockedProfileStore::new(store_path.as_ref());
        let store = locked.unlock(passphrase)?;
        if !store.profile_marker_exists(&profile)? {
            return Err(ProductionSessionError::ProfileMarkerMissing);
        }
        let material = load_session_runtime_material(&store, &profile)?;
        let draft = load_latest_session_draft(&store, &profile)?
            .ok_or(ProductionSessionError::SessionDraftMissing)?;
        let local_noise_static = store
            .get(&production_latest_pairing_noise_static_record_id())?
            .map(decode_production_noise_static_private_key_record)
            .transpose()?
            .ok_or(ProductionSessionError::NoiseStaticPrivateKeyMissing)?;
        if local_noise_static.keypair.public_key() != draft.local_noise_static_public_key {
            return Err(ProductionSessionError::NoiseStaticKeyMismatch);
        }
        let transport_state = load_session_transport_state(&store, &profile, &draft)?
            .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
        let session_transport_ready = transport_state.channel_id == material.channel_id
            && transport_state.local_role == draft.local_role
            && transport_state.remote_contact_id == material.remote_contact_id
            && transport_state.remote_noise_static_public_key
                == draft.remote_noise_static_public_key
            && transport_state.transport_state_created
            && matches!(
                (
                    draft.local_role,
                    transport_state.handshake_message_kind.as_str()
                ),
                (SessionRole::CanonicalDialer, "reply") | (SessionRole::Responder, "finish")
            );
        if !session_transport_ready {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let envelope = Envelope::decode(envelope_payload)?;
        if envelope.message_number == 0
            || envelope.channel_id != material.channel_id
            || envelope.message_type != MessageType::Control
        {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let mut replay_window = store
            .load_replay_window(&production_replay_record_id(&draft.channel_id))?
            .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
        replay_window.accept(envelope.message_number)?;
        let plaintext = match draft.local_role {
            SessionRole::CanonicalDialer => {
                let state = store
                    .get(&production_pending_handshake_initiator_state_record_id())?
                    .map(|record| {
                        decode_production_handshake_initiator_state_record(
                            record,
                            &profile,
                            &draft.channel_id,
                        )
                    })
                    .transpose()?
                    .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
                let transport = create_noise_xx_stateless_initiator_transport(
                    &draft.safety_transcript,
                    &local_noise_static.keypair,
                    &state.initiator_ephemeral_private,
                    &transport_state.handshake_message,
                )
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                if transport.remote_static() != draft.remote_noise_static_public_key {
                    return Err(ProductionSessionError::NoiseStaticKeyMismatch);
                }
                transport
                    .decrypt_with_nonce(
                        production_message_transport_nonce(
                            envelope.message_number,
                            &envelope.message_type,
                        )?,
                        &envelope.padded_ciphertext,
                    )
                    .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?
            }
            SessionRole::Responder => {
                let state = store
                    .get(&production_pending_handshake_initiator_state_record_id())?
                    .map(|record| {
                        decode_production_handshake_responder_state_record(
                            record,
                            &profile,
                            &draft.channel_id,
                        )
                    })
                    .transpose()?
                    .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
                let transport = create_noise_xx_stateless_responder_transport(
                    &draft.safety_transcript,
                    &local_noise_static.keypair,
                    &state.init_message,
                    &state.responder_ephemeral_private,
                    &transport_state.handshake_message,
                )
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                if transport.remote_static() != draft.remote_noise_static_public_key {
                    return Err(ProductionSessionError::NoiseStaticKeyMismatch);
                }
                transport
                    .decrypt_with_nonce(
                        production_message_transport_nonce(
                            envelope.message_number,
                            &envelope.message_type,
                        )?,
                        &envelope.padded_ciphertext,
                    )
                    .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?
            }
        };
        if plaintext.remote_static != draft.remote_noise_static_public_key
            || plaintext.key_material_exposed
        {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let control_plaintext =
            EndpointUpdateControlPlaintext::decode(trim_padding(&plaintext.plaintext))?;
        let update = PairwiseEndpointUpdate::for_existing_encrypted_session(
            &material.remote_endpoint,
            control_plaintext.new_endpoint().clone(),
            EndpointUpdateChannel::ExistingEncryptedSession,
        )?;
        let updated_endpoint = PairwiseRendezvousEndpoint::new(
            update.contact_id().clone(),
            update.new_endpoint().clone(),
            RendezvousEndpointScope::PairwiseContact,
            RendezvousEndpointIdentityBinding::TransportScoped,
        )?;
        let endpoint_record = EncryptedRecord::new(
            ProductionRecordKind::RendezvousEndpointState,
            EncryptedRecordScope::contact(profile.clone(), draft.remote_contact_id.clone()),
            b"sqlcipher-page-encryption-v1".to_vec(),
            updated_endpoint.encode_state().into_bytes(),
        )
        .map_err(ProductionStorageError::from)?;
        store.put(
            &production_endpoint_state_record_id(&draft.channel_id, &draft.remote_contact_id),
            &endpoint_record,
        )?;
        store.delete(&production_endpoint_status_record_id(
            &draft.channel_id,
            &draft.remote_contact_id,
        ))?;
        store.save_replay_window(
            &production_replay_record_id(&draft.channel_id),
            EncryptedRecordScope::contact(profile, material.remote_contact_id),
            &replay_window,
        )?;
        Ok(ProductionEndpointUpdateControlEnvelopeImportSummary {
            storage_opened: true,
            runtime_material_reconstructable: true,
            envelope_read: !envelope_payload.is_empty(),
            envelope_decodable: true,
            envelope_message_type_control: true,
            session_transport_ready,
            replay_window_loaded: true,
            replay_accepted: true,
            control_plaintext_decrypted: true,
            endpoint_update_applied: true,
            remote_endpoint_state_written: true,
            stale_endpoint_status_cleared: true,
            endpoint_plaintext_exposed: false,
            network_receive_attempted: false,
            key_material_exposed: false,
            transport_io_opened: false,
            runtime_messaging_enabled: false,
        })
    }

    pub fn production_message_inbound_decrypt_import(
        store_path: impl AsRef<std::path::Path>,
        profile: ProfileName,
        passphrase: &ProfilePassphrase,
        envelope_payload: &str,
        ttl_seconds: u64,
    ) -> Result<ProductionMessageInboundDecryptImportSummary, ProductionSessionError> {
        let ttl_seconds = production_message_ttl_seconds_validate(ttl_seconds)?;
        let locked = LockedProfileStore::new(store_path.as_ref());
        let store = locked.unlock(passphrase)?;
        if !store.profile_marker_exists(&profile)? {
            return Err(ProductionSessionError::ProfileMarkerMissing);
        }
        let material = load_session_runtime_material(&store, &profile)?;
        let draft = load_latest_session_draft(&store, &profile)?
            .ok_or(ProductionSessionError::SessionDraftMissing)?;
        let local_noise_static = store
            .get(&production_latest_pairing_noise_static_record_id())?
            .map(decode_production_noise_static_private_key_record)
            .transpose()?
            .ok_or(ProductionSessionError::NoiseStaticPrivateKeyMissing)?;
        if local_noise_static.keypair.public_key() != draft.local_noise_static_public_key {
            return Err(ProductionSessionError::NoiseStaticKeyMismatch);
        }
        let transport_state = load_session_transport_state(&store, &profile, &draft)?
            .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
        let session_transport_ready = transport_state.channel_id == material.channel_id
            && transport_state.local_role == draft.local_role
            && transport_state.remote_contact_id == material.remote_contact_id
            && transport_state.remote_noise_static_public_key
                == draft.remote_noise_static_public_key
            && transport_state.transport_state_created
            && matches!(
                (
                    draft.local_role,
                    transport_state.handshake_message_kind.as_str()
                ),
                (SessionRole::CanonicalDialer, "reply") | (SessionRole::Responder, "finish")
            );
        if !session_transport_ready {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let envelope = Envelope::decode(envelope_payload)?;
        if envelope.message_number == 0
            || envelope.channel_id != material.channel_id
            || envelope.message_type != MessageType::Data
        {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let mut replay_window = store
            .load_replay_window(&production_replay_record_id(&draft.channel_id))?
            .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
        replay_window.accept(envelope.message_number)?;
        let plaintext = match draft.local_role {
            SessionRole::CanonicalDialer => {
                let state = store
                    .get(&production_pending_handshake_initiator_state_record_id())?
                    .map(|record| {
                        decode_production_handshake_initiator_state_record(
                            record,
                            &profile,
                            &draft.channel_id,
                        )
                    })
                    .transpose()?
                    .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
                let transport = create_noise_xx_stateless_initiator_transport(
                    &draft.safety_transcript,
                    &local_noise_static.keypair,
                    &state.initiator_ephemeral_private,
                    &transport_state.handshake_message,
                )
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                if transport.remote_static() != draft.remote_noise_static_public_key {
                    return Err(ProductionSessionError::NoiseStaticKeyMismatch);
                }
                transport
                    .decrypt_with_nonce(
                        production_message_transport_nonce(
                            envelope.message_number,
                            &envelope.message_type,
                        )?,
                        &envelope.padded_ciphertext,
                    )
                    .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?
            }
            SessionRole::Responder => {
                let state = store
                    .get(&production_pending_handshake_initiator_state_record_id())?
                    .map(|record| {
                        decode_production_handshake_responder_state_record(
                            record,
                            &profile,
                            &draft.channel_id,
                        )
                    })
                    .transpose()?
                    .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
                let transport = create_noise_xx_stateless_responder_transport(
                    &draft.safety_transcript,
                    &local_noise_static.keypair,
                    &state.init_message,
                    &state.responder_ephemeral_private,
                    &transport_state.handshake_message,
                )
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                if transport.remote_static() != draft.remote_noise_static_public_key {
                    return Err(ProductionSessionError::NoiseStaticKeyMismatch);
                }
                transport
                    .decrypt_with_nonce(
                        production_message_transport_nonce(
                            envelope.message_number,
                            &envelope.message_type,
                        )?,
                        &envelope.padded_ciphertext,
                    )
                    .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?
            }
        };
        if plaintext.remote_static != draft.remote_noise_static_public_key
            || plaintext.key_material_exposed
            || trim_padding(&plaintext.plaintext).is_empty()
        {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let trimmed_plaintext = trim_padding(&plaintext.plaintext);
        let received_record_id = production_received_message_record_id(
            &material.channel_id,
            &material.remote_contact_id,
            envelope.message_number,
        );
        if store.get(&received_record_id)?.is_some() {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let received = ReceivedMessageRecord::new_with_retention(
            material.remote_contact_id.clone(),
            envelope.message_number,
            MessageType::Data,
            trimmed_plaintext,
            production_now_ms(),
            ttl_seconds,
        )?;
        let received_record = EncryptedRecord::new(
            ProductionRecordKind::ReceivedMessage,
            EncryptedRecordScope::contact(profile.clone(), material.remote_contact_id.clone()),
            b"sqlcipher-page-encryption-v1".to_vec(),
            received.encode().into_bytes(),
        )
        .map_err(ProductionStorageError::from)?;
        store.put(&received_record_id, &received_record)?;
        store.save_replay_window(
            &production_replay_record_id(&draft.channel_id),
            EncryptedRecordScope::contact(profile, material.remote_contact_id),
            &replay_window,
        )?;
        Ok(ProductionMessageInboundDecryptImportSummary {
            storage_opened: true,
            runtime_material_reconstructable: true,
            envelope_read: !envelope_payload.is_empty(),
            envelope_decodable: true,
            session_transport_ready,
            replay_window_loaded: true,
            replay_accepted: true,
            plaintext_decrypted: true,
            plaintext_exposed: false,
            received_message_written: true,
            replay_window_committed: true,
            network_receive_attempted: false,
            key_material_exposed: false,
            transport_io_opened: false,
            runtime_messaging_enabled: false,
        })
    }

    pub fn production_message_received_status(
        store_path: impl AsRef<std::path::Path>,
        profile: ProfileName,
        passphrase: &ProfilePassphrase,
        message_number: u64,
    ) -> Result<ProductionMessageReceivedStatusSummary, ProductionSessionError> {
        if message_number == 0 {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let locked = LockedProfileStore::new(store_path.as_ref());
        let store = locked.unlock(passphrase)?;
        if !store.profile_marker_exists(&profile)? {
            return Err(ProductionSessionError::ProfileMarkerMissing);
        }
        let material = load_session_runtime_material(&store, &profile)?;
        let received_record_id = production_received_message_record_id(
            &material.channel_id,
            &material.remote_contact_id,
            message_number,
        );
        let mut received = store
            .get(&received_record_id)?
            .map(|record| {
                if record.kind != ProductionRecordKind::ReceivedMessage {
                    return Err(ProductionSessionError::UnexpectedEnvelope);
                }
                let state = String::from_utf8(record.sealed_body)
                    .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                ReceivedMessageRecord::decode(&state)
            })
            .transpose()?;
        let observed_at_ms = production_now_ms();
        let mut expired_received_message_purged = false;
        if received
            .as_ref()
            .is_some_and(|received| received.is_expired_at(observed_at_ms))
        {
            store.delete(&received_record_id)?;
            received = None;
            expired_received_message_purged = true;
        }
        let received_message_matches_session = received.as_ref().is_some_and(|received| {
            received.contact_id == material.remote_contact_id
                && received.message_number == message_number
                && received.message_type == MessageType::Data
                && !received.plaintext.is_empty()
        });
        Ok(ProductionMessageReceivedStatusSummary {
            storage_opened: true,
            runtime_material_reconstructable: true,
            received_message_record_present: received.is_some(),
            received_message_record_decodable: received.is_some(),
            received_message_matches_session,
            expired_received_message_purged,
            plaintext_exposed: false,
            network_receive_attempted: false,
            key_material_exposed: false,
            transport_io_opened: false,
            runtime_messaging_enabled: false,
        })
    }

    pub fn production_message_received_export(
        store_path: impl AsRef<std::path::Path>,
        profile: ProfileName,
        passphrase: &ProfilePassphrase,
        message_number: u64,
    ) -> Result<ProductionMessageReceivedExport, ProductionSessionError> {
        if message_number == 0 {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let locked = LockedProfileStore::new(store_path.as_ref());
        let store = locked.unlock(passphrase)?;
        if !store.profile_marker_exists(&profile)? {
            return Err(ProductionSessionError::ProfileMarkerMissing);
        }
        let material = load_session_runtime_material(&store, &profile)?;
        let received_record_id = production_received_message_record_id(
            &material.channel_id,
            &material.remote_contact_id,
            message_number,
        );
        let received = store
            .get(&received_record_id)?
            .map(|record| {
                if record.kind != ProductionRecordKind::ReceivedMessage {
                    return Err(ProductionSessionError::UnexpectedEnvelope);
                }
                let state = String::from_utf8(record.sealed_body)
                    .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
                ReceivedMessageRecord::decode(&state)
            })
            .transpose()?
            .ok_or(ProductionSessionError::UnexpectedEnvelope)?;
        let received_message_matches_session = received.contact_id == material.remote_contact_id
            && received.message_number == message_number
            && received.message_type == MessageType::Data
            && !received.plaintext.is_empty();
        if !received_message_matches_session {
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        let observed_at_ms = production_now_ms();
        if received.is_expired_at(observed_at_ms) {
            store.delete(&received_record_id)?;
            return Err(ProductionSessionError::UnexpectedEnvelope);
        }
        Ok(ProductionMessageReceivedExport {
            storage_opened: true,
            runtime_material_reconstructable: true,
            received_message_record_present: true,
            received_message_record_decodable: true,
            received_message_matches_session,
            created_at_ms: received.created_at_ms,
            ttl_seconds: received.ttl_seconds,
            expires_at_ms: received.expires_at_ms(),
            expired: received.is_expired_at(observed_at_ms),
            export_payload: received.plaintext,
            plaintext_exposed: false,
            network_receive_attempted: false,
            key_material_exposed: false,
            transport_io_opened: false,
            runtime_messaging_enabled: false,
        })
    }

    pub fn production_message_transcript_export(
        store_path: impl AsRef<std::path::Path>,
        profile: ProfileName,
        passphrase: &ProfilePassphrase,
    ) -> Result<ProductionMessageTranscriptExport, ProductionSessionError> {
        let locked = LockedProfileStore::new(store_path.as_ref());
        let store = locked.unlock(passphrase)?;
        if !store.profile_marker_exists(&profile)? {
            return Err(ProductionSessionError::ProfileMarkerMissing);
        }
        let material = load_session_runtime_material(&store, &profile)?;
        let mut entries = Vec::new();
        let mut expired_messages_purged = 0;
        let observed_at_ms = production_now_ms();

        for (record_id, record) in store.records_with_id_prefix("sent_")? {
            if record.kind != ProductionRecordKind::SentMessage {
                return Err(ProductionSessionError::UnexpectedEnvelope);
            }
            let state = String::from_utf8(record.sealed_body)
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
            let sent = SentMessageRecord::decode(&state)?;
            if sent.contact_id == material.remote_contact_id
                && sent.message_type == MessageType::Data
                && !sent.plaintext.is_empty()
                && record_id
                    == production_sent_message_record_id(
                        &material.channel_id,
                        &material.remote_contact_id,
                        sent.message_number,
                    )
            {
                if sent.is_expired_at(observed_at_ms) {
                    store.delete(&record_id)?;
                    store.delete(&production_local_message_index_record_id(
                        &material.channel_id,
                        &material.remote_contact_id,
                        sent.message_number,
                    ))?;
                    store.delete(&production_message_envelope_record_id(
                        &material.channel_id,
                        sent.message_number,
                        MessageType::Data,
                    ))?;
                    expired_messages_purged += 1;
                    continue;
                }
                entries.push(ProductionMessageTranscriptEntry {
                    direction: "sent",
                    message_number: sent.message_number,
                    created_at_ms: sent.created_at_ms,
                    ttl_seconds: sent.ttl_seconds,
                    expires_at_ms: sent.expires_at_ms(),
                    expired: sent.is_expired_at(observed_at_ms),
                    outbound_delivery_state: Some(sent.delivery_state.tag()),
                    outbound_failure_kind: sent.failure_kind.clone(),
                    outbound_retryable: sent.delivery_state.retryable(),
                    plaintext: sent.plaintext,
                });
            }
        }

        for (record_id, record) in store.records_with_id_prefix("received_")? {
            if record.kind != ProductionRecordKind::ReceivedMessage {
                return Err(ProductionSessionError::UnexpectedEnvelope);
            }
            let state = String::from_utf8(record.sealed_body)
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
            let received = ReceivedMessageRecord::decode(&state)?;
            if received.contact_id == material.remote_contact_id
                && received.message_type == MessageType::Data
                && !received.plaintext.is_empty()
                && record_id
                    == production_received_message_record_id(
                        &material.channel_id,
                        &material.remote_contact_id,
                        received.message_number,
                    )
            {
                if received.is_expired_at(observed_at_ms) {
                    store.delete(&record_id)?;
                    expired_messages_purged += 1;
                    continue;
                }
                entries.push(ProductionMessageTranscriptEntry {
                    direction: "received",
                    message_number: received.message_number,
                    created_at_ms: received.created_at_ms,
                    ttl_seconds: received.ttl_seconds,
                    expires_at_ms: received.expires_at_ms(),
                    expired: received.is_expired_at(observed_at_ms),
                    outbound_delivery_state: None,
                    outbound_failure_kind: None,
                    outbound_retryable: false,
                    plaintext: received.plaintext,
                });
            }
        }

        entries.sort_by_key(|entry| {
            (
                entry.message_number,
                if entry.direction == "sent" { 0 } else { 1 },
            )
        });
        Ok(ProductionMessageTranscriptExport {
            storage_opened: true,
            runtime_material_reconstructable: true,
            entries,
            expired_messages_purged,
            plaintext_exposed: false,
            network_io_attempted: false,
            key_material_exposed: false,
            transport_io_opened: false,
            runtime_messaging_enabled: false,
        })
    }

    pub fn production_message_transcript_tsv(
        entries: &[ProductionMessageTranscriptEntry],
    ) -> Result<String, ProductionSessionError> {
        let mut out = String::from(
            "direction\tmessage_number\tcreated_at_ms\tttl_seconds\texpires_at_ms\tmessage\n",
        );
        for entry in entries {
            let message = String::from_utf8(entry.plaintext.clone())
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
            out.push_str(entry.direction);
            out.push('\t');
            out.push_str(&entry.message_number.to_string());
            out.push('\t');
            out.push_str(&entry.created_at_ms.to_string());
            out.push('\t');
            out.push_str(&entry.ttl_seconds.to_string());
            out.push('\t');
            out.push_str(
                &entry
                    .expires_at_ms
                    .map(|value| value.to_string())
                    .unwrap_or_else(|| "none".to_string()),
            );
            out.push('\t');
            out.push_str(&escape_transcript_tsv_cell(&message));
            out.push('\n');
        }
        Ok(out)
    }

    pub fn production_conversation_delete(
        store_path: impl AsRef<std::path::Path>,
        profile: ProfileName,
        passphrase: &ProfilePassphrase,
    ) -> Result<ProductionConversationDeleteSummary, ProductionSessionError> {
        let locked = LockedProfileStore::new(store_path.as_ref());
        let store = locked.unlock(passphrase)?;
        if !store.profile_marker_exists(&profile)? {
            return Err(ProductionSessionError::ProfileMarkerMissing);
        }
        let material = load_session_runtime_material(&store, &profile)?;
        let mut sent_messages_deleted = 0;
        let mut received_messages_deleted = 0;
        let mut message_envelopes_deleted = 0;
        let mut local_message_indexes_deleted = 0;

        for (record_id, record) in store.records_with_id_prefix("sent_")? {
            if record.kind != ProductionRecordKind::SentMessage {
                return Err(ProductionSessionError::UnexpectedEnvelope);
            }
            let state = String::from_utf8(record.sealed_body)
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
            let sent = SentMessageRecord::decode(&state)?;
            if sent.contact_id != material.remote_contact_id
                || sent.message_type != MessageType::Data
                || record_id
                    != production_sent_message_record_id(
                        &material.channel_id,
                        &material.remote_contact_id,
                        sent.message_number,
                    )
            {
                continue;
            }
            store.delete(&record_id)?;
            sent_messages_deleted += 1;

            let index_id = production_local_message_index_record_id(
                &material.channel_id,
                &material.remote_contact_id,
                sent.message_number,
            );
            if store.get(&index_id)?.is_some() {
                store.delete(&index_id)?;
                local_message_indexes_deleted += 1;
            }

            let envelope_id = production_message_envelope_record_id(
                &material.channel_id,
                sent.message_number,
                MessageType::Data,
            );
            if store.get(&envelope_id)?.is_some() {
                store.delete(&envelope_id)?;
                message_envelopes_deleted += 1;
            }
        }

        for (record_id, record) in store.records_with_id_prefix("received_")? {
            if record.kind != ProductionRecordKind::ReceivedMessage {
                return Err(ProductionSessionError::UnexpectedEnvelope);
            }
            let state = String::from_utf8(record.sealed_body)
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
            let received = ReceivedMessageRecord::decode(&state)?;
            if received.contact_id != material.remote_contact_id
                || received.message_type != MessageType::Data
                || record_id
                    != production_received_message_record_id(
                        &material.channel_id,
                        &material.remote_contact_id,
                        received.message_number,
                    )
            {
                continue;
            }
            store.delete(&record_id)?;
            received_messages_deleted += 1;
        }

        for (record_id, record) in store.records_with_id_prefix("message_")? {
            if record.kind != ProductionRecordKind::MessageEnvelope {
                return Err(ProductionSessionError::UnexpectedEnvelope);
            }
            let state = String::from_utf8(record.sealed_body)
                .map_err(|_| ProductionSessionError::UnexpectedEnvelope)?;
            if Envelope::decode(&state)
                .map(|envelope| envelope.channel_id == material.channel_id)
                .unwrap_or(false)
            {
                store.delete(&record_id)?;
                message_envelopes_deleted += 1;
            }
        }

        let counter_id =
            production_message_counter_record_id(&material.channel_id, &material.remote_contact_id);
        let message_counter_deleted = store.get(&counter_id)?.is_some();
        if message_counter_deleted {
            store.delete(&counter_id)?;
        }
        let conversation_records_deleted = sent_messages_deleted
            + received_messages_deleted
            + message_envelopes_deleted
            + local_message_indexes_deleted
            + usize::from(message_counter_deleted);
        let conversation_dek_deleted = message_counter_deleted;
        let message_key_records_deleted = message_envelopes_deleted > 0
            || sent_messages_deleted > 0
            || received_messages_deleted > 0
            || local_message_indexes_deleted > 0;
        let crypto_erasure_performed = conversation_dek_deleted
            && message_key_records_deleted
            && conversation_records_deleted > 0;

        Ok(ProductionConversationDeleteSummary {
            storage_opened: true,
            runtime_material_reconstructable: true,
            sent_messages_deleted,
            received_messages_deleted,
            message_envelopes_deleted,
            local_message_indexes_deleted,
            message_counter_deleted,
            conversation_records_deleted,
            conversation_dek_deleted,
            message_key_records_deleted,
            crypto_erasure_performed,
            session_records_preserved: load_latest_session_draft(&store, &profile)?.is_some(),
            plaintext_exposed: false,
            key_material_exposed: false,
            transport_io_opened: false,
            runtime_messaging_enabled: false,
        })
    }

    fn escape_transcript_tsv_cell(value: &str) -> String {
        let mut escaped = String::with_capacity(value.len());
        for ch in value.chars() {
            match ch {
                '\\' => escaped.push_str("\\\\"),
                '\t' => escaped.push_str("\\t"),
                '\r' => escaped.push_str("\\r"),
                '\n' => escaped.push_str("\\n"),
                _ => escaped.push(ch),
            }
        }
        escaped
    }

