    pub fn production_high_risk_threat_model_claim_boundary_summary(
    ) -> ProductionHighRiskThreatModelClaimBoundarySummary {
        let app_matrix_required = true;
        let public_copy_matrix_required = true;
        let compromised_endpoint_not_protected = PRODUCTION_HIGH_RISK_THREAT_MODEL_MATRIX
            .iter()
            .any(|entry| {
                entry.attacker_class == "compromised_endpoint"
                    && entry.status == ProductionHighRiskProtectionStatus::NotProtected
            });
        let direct_coercion_not_protected =
            PRODUCTION_HIGH_RISK_THREAT_MODEL_MATRIX
                .iter()
                .any(|entry| {
                    entry.attacker_class == "direct_coercion"
                        && entry.status == ProductionHighRiskProtectionStatus::NotProtected
                });
        let global_traffic_correlation_not_protected = PRODUCTION_HIGH_RISK_THREAT_MODEL_MATRIX
            .iter()
            .any(|entry| {
                entry.attacker_class == "global_traffic_correlation"
                    && entry.status == ProductionHighRiskProtectionStatus::NotProtected
            });
        let audited_security_claim_allowed = false;
        let briar_cwtch_equivalence_claim_allowed = false;
        let boundary_closed = app_matrix_required
            && public_copy_matrix_required
            && compromised_endpoint_not_protected
            && direct_coercion_not_protected
            && global_traffic_correlation_not_protected
            && !audited_security_claim_allowed
            && !briar_cwtch_equivalence_claim_allowed
            && PRODUCTION_HIGH_RISK_THREAT_MODEL_MATRIX.len() == 8
            && PRODUCTION_HIGH_RISK_THREAT_MODEL_MATRIX
                .iter()
                .all(|entry| {
                    PRODUCTION_HIGH_RISK_CLAIMABLE_STATUSES.contains(&entry.status)
                        || entry.status == ProductionHighRiskProtectionStatus::NotProtected
                })
            && PRODUCTION_HIGH_RISK_ORDINARY_USE_CLAIMS.contains(&"no_phone_number")
            && PRODUCTION_HIGH_RISK_ORDINARY_USE_CLAIMS.contains(&"no_email")
            && PRODUCTION_HIGH_RISK_ORDINARY_USE_CLAIMS.contains(&"no_global_account")
            && PRODUCTION_HIGH_RISK_ORDINARY_USE_CLAIMS.contains(&"no_central_contact_discovery")
            && PRODUCTION_HIGH_RISK_ORDINARY_USE_CLAIMS
                .contains(&"user_mediated_encrypted_exchange")
            && PRODUCTION_HIGH_RISK_FORBIDDEN_CLAIMS.contains(&"audited_security")
            && PRODUCTION_HIGH_RISK_FORBIDDEN_CLAIMS.contains(&"briar_cwtch_equivalent")
            && PRODUCTION_HIGH_RISK_FORBIDDEN_CLAIMS.contains(&"compromised_endpoint_safe")
            && PRODUCTION_HIGH_RISK_FORBIDDEN_CLAIMS.contains(&"coercion_safe")
            && PRODUCTION_HIGH_RISK_FORBIDDEN_CLAIMS
                .contains(&"full_global_traffic_correlation_safe");

        ProductionHighRiskThreatModelClaimBoundarySummary {
            matrix: PRODUCTION_HIGH_RISK_THREAT_MODEL_MATRIX,
            claimable_statuses: PRODUCTION_HIGH_RISK_CLAIMABLE_STATUSES,
            forbidden_claims: PRODUCTION_HIGH_RISK_FORBIDDEN_CLAIMS,
            ordinary_use_claims: PRODUCTION_HIGH_RISK_ORDINARY_USE_CLAIMS,
            app_matrix_required,
            public_copy_matrix_required,
            compromised_endpoint_not_protected,
            direct_coercion_not_protected,
            global_traffic_correlation_not_protected,
            audited_security_claim_allowed,
            briar_cwtch_equivalence_claim_allowed,
            boundary_closed,
        }
    }

    pub fn production_session_lifecycle_transition(
        before: ProductionSessionLifecycleState,
        event: ProductionSessionLifecycleEvent,
    ) -> ProductionSessionLifecycleTransition {
        let terminal_blocked = before.terminal()
            && !matches!(
                event,
                ProductionSessionLifecycleEvent::DeleteLocal
                    | ProductionSessionLifecycleEvent::RevokeRePairRequired
            );
        if terminal_blocked {
            return ProductionSessionLifecycleTransition {
                before,
                event,
                after: before,
                accepted: false,
                imported: false,
                delivered: false,
                terminal_blocked: true,
                reason: "terminal_state_cannot_be_promoted",
            };
        }

        let (after, accepted, imported, delivered, reason) = match (before, event) {
            (
                ProductionSessionLifecycleState::Created,
                ProductionSessionLifecycleEvent::PairInvite,
            ) => (
                ProductionSessionLifecycleState::Paired,
                true,
                false,
                false,
                "paired_after_invite",
            ),
            (
                ProductionSessionLifecycleState::Paired,
                ProductionSessionLifecycleEvent::ConfirmSafety,
            ) => (
                ProductionSessionLifecycleState::Verified,
                true,
                false,
                false,
                "verified_after_safety_confirm",
            ),
            (
                ProductionSessionLifecycleState::Verified
                | ProductionSessionLifecycleState::Imported,
                ProductionSessionLifecycleEvent::QueueOutbound,
            )
            | (
                ProductionSessionLifecycleState::Pending,
                ProductionSessionLifecycleEvent::QueueOutbound,
            ) => (
                ProductionSessionLifecycleState::Pending,
                true,
                false,
                false,
                "outbound_pending",
            ),
            (
                ProductionSessionLifecycleState::Verified
                | ProductionSessionLifecycleState::Pending
                | ProductionSessionLifecycleState::Imported,
                ProductionSessionLifecycleEvent::ImportInbound,
            ) => (
                ProductionSessionLifecycleState::Imported,
                true,
                true,
                false,
                "inbound_imported_after_replay_and_decrypt",
            ),
            (
                ProductionSessionLifecycleState::Pending,
                ProductionSessionLifecycleEvent::MarkOutboundDelivered,
            ) => (
                ProductionSessionLifecycleState::Pending,
                true,
                false,
                true,
                "outbound_delivery_recorded",
            ),
            (
                ProductionSessionLifecycleState::Pending,
                ProductionSessionLifecycleEvent::CancelOutbound,
            ) => (
                ProductionSessionLifecycleState::Canceled,
                true,
                false,
                false,
                "outbound_canceled_terminal",
            ),
            (_, ProductionSessionLifecycleEvent::DeleteLocal) => (
                ProductionSessionLifecycleState::Deleted,
                true,
                false,
                false,
                "local_delete_terminal",
            ),
            (_, ProductionSessionLifecycleEvent::RevokeRePairRequired) => (
                ProductionSessionLifecycleState::RevokedRePairRequired,
                true,
                false,
                false,
                "revoked_re_pair_required_terminal",
            ),
            _ => (before, false, false, false, "transition_not_allowed"),
        };

        ProductionSessionLifecycleTransition {
            before,
            event,
            after,
            accepted,
            imported,
            delivered,
            terminal_blocked: false,
            reason,
        }
    }

    pub fn production_pairwise_invite_import_decision(
        payload_decodable: bool,
        supported_payload: bool,
        duplicate_contact: bool,
        already_paired: bool,
        identity_matches_expected: bool,
        revoked_re_pair_required: bool,
    ) -> ProductionPairwiseInviteImportDecision {
        let failure_kind = if !payload_decodable {
            Some(ProductionPairwiseInviteImportFailureKind::Malformed)
        } else if !supported_payload {
            Some(ProductionPairwiseInviteImportFailureKind::Unsupported)
        } else if revoked_re_pair_required {
            Some(ProductionPairwiseInviteImportFailureKind::RevokedRePairRequired)
        } else if already_paired {
            Some(ProductionPairwiseInviteImportFailureKind::AlreadyPaired)
        } else if duplicate_contact {
            Some(ProductionPairwiseInviteImportFailureKind::Duplicate)
        } else if !identity_matches_expected {
            Some(ProductionPairwiseInviteImportFailureKind::IdentityMismatch)
        } else {
            None
        };
        ProductionPairwiseInviteImportDecision {
            accepted: failure_kind.is_none(),
            failure_kind,
            duplicate_contact: failure_kind
                == Some(ProductionPairwiseInviteImportFailureKind::Duplicate),
            already_paired: failure_kind
                == Some(ProductionPairwiseInviteImportFailureKind::AlreadyPaired),
            identity_mismatch: failure_kind
                == Some(ProductionPairwiseInviteImportFailureKind::IdentityMismatch),
            revoked_re_pair_required: failure_kind
                == Some(ProductionPairwiseInviteImportFailureKind::RevokedRePairRequired),
            generic_error: false,
            next_action: failure_kind
                .map(ProductionPairwiseInviteImportFailureKind::next_action)
                .unwrap_or("compare_safety_transcript_before_trust"),
        }
    }

    pub fn production_pairwise_safety_verification_decision(
        safety_transcript_present: bool,
        confirmed_match: bool,
        marked_mismatch: bool,
        revoked_re_pair_required: bool,
    ) -> ProductionPairwiseSafetyVerificationDecision {
        let state = if revoked_re_pair_required {
            ProductionPairwiseSafetyVerificationState::RevokedRePairRequired
        } else if marked_mismatch {
            ProductionPairwiseSafetyVerificationState::MarkedMismatch
        } else if safety_transcript_present && confirmed_match {
            ProductionPairwiseSafetyVerificationState::ConfirmedMatch
        } else {
            ProductionPairwiseSafetyVerificationState::Compare
        };
        let re_pair_required = matches!(
            state,
            ProductionPairwiseSafetyVerificationState::MarkedMismatch
                | ProductionPairwiseSafetyVerificationState::RevokedRePairRequired
        );
        ProductionPairwiseSafetyVerificationDecision {
            state,
            compare_required: !matches!(
                state,
                ProductionPairwiseSafetyVerificationState::ConfirmedMatch
            ),
            confirm_match_allowed: safety_transcript_present && !re_pair_required,
            mismatch_blocks_trust: matches!(
                state,
                ProductionPairwiseSafetyVerificationState::MarkedMismatch
            ),
            re_pair_required,
            generic_error: false,
            next_action: match state {
                ProductionPairwiseSafetyVerificationState::Compare => {
                    "compare_safety_number_and_phrase"
                }
                ProductionPairwiseSafetyVerificationState::ConfirmedMatch => {
                    "save_pairwise_session_draft"
                }
                ProductionPairwiseSafetyVerificationState::MarkedMismatch => {
                    "stop_and_rebuild_with_fresh_invite"
                }
                ProductionPairwiseSafetyVerificationState::RevokedRePairRequired => {
                    "discard_old_session_and_re_pair"
                }
            },
        }
    }

    pub fn production_message_envelope_import_decision(
        payload_present: bool,
        payload_decodable: bool,
        payload_oversized: bool,
        payload_corrupted: bool,
        message_type_data: bool,
        replay_accepted: bool,
        duplicate_envelope: bool,
    ) -> ProductionMessageEnvelopeImportDecision {
        let failure_kind = if payload_oversized {
            Some(ProductionMessageEnvelopeImportFailureKind::Oversized)
        } else if !payload_present {
            Some(ProductionMessageEnvelopeImportFailureKind::Malformed)
        } else if payload_corrupted {
            Some(ProductionMessageEnvelopeImportFailureKind::Corrupted)
        } else if !payload_decodable {
            Some(ProductionMessageEnvelopeImportFailureKind::Malformed)
        } else if !message_type_data {
            Some(ProductionMessageEnvelopeImportFailureKind::WrongType)
        } else if duplicate_envelope {
            Some(ProductionMessageEnvelopeImportFailureKind::Duplicate)
        } else if !replay_accepted {
            Some(ProductionMessageEnvelopeImportFailureKind::ReplayRejected)
        } else {
            None
        };
        ProductionMessageEnvelopeImportDecision {
            accepted: failure_kind.is_none(),
            failure_kind,
            imported: failure_kind.is_none(),
            delivered: failure_kind.is_none(),
            plaintext_returned: false,
            path_returned: false,
            key_material_exposed: false,
            generic_error: false,
            next_action: failure_kind
                .map(ProductionMessageEnvelopeImportFailureKind::next_action)
                .unwrap_or("import_message_envelope"),
        }
    }

    pub fn production_manual_envelope_outbound_decision(
        encrypted_envelope_exported: bool,
        sent_copy_present: bool,
        received_copy_present: bool,
        duplicate_import: bool,
        stale_or_replayed_import: bool,
        canceled: bool,
    ) -> ProductionManualEnvelopeOutboundDecision {
        let state = if canceled {
            ProductionManualEnvelopeOutboundState::Canceled
        } else if duplicate_import {
            ProductionManualEnvelopeOutboundState::DuplicateImport
        } else if stale_or_replayed_import {
            ProductionManualEnvelopeOutboundState::StaleOrReplayedImport
        } else if !encrypted_envelope_exported {
            ProductionManualEnvelopeOutboundState::ReadyToExport
        } else if !sent_copy_present {
            ProductionManualEnvelopeOutboundState::Exported
        } else {
            ProductionManualEnvelopeOutboundState::WaitingForReply
        };
        let terminal = state == ProductionManualEnvelopeOutboundState::Canceled;
        ProductionManualEnvelopeOutboundDecision {
            state,
            export_allowed: state == ProductionManualEnvelopeOutboundState::ReadyToExport,
            import_allowed: state == ProductionManualEnvelopeOutboundState::Exported,
            retry_allowed: matches!(
                state,
                ProductionManualEnvelopeOutboundState::DuplicateImport
                    | ProductionManualEnvelopeOutboundState::StaleOrReplayedImport
            ),
            cancel_allowed: matches!(
                state,
                ProductionManualEnvelopeOutboundState::ReadyToExport
                    | ProductionManualEnvelopeOutboundState::Exported
                    | ProductionManualEnvelopeOutboundState::WaitingForReply
                    | ProductionManualEnvelopeOutboundState::DuplicateImport
                    | ProductionManualEnvelopeOutboundState::StaleOrReplayedImport
            ),
            reply_allowed: received_copy_present && !terminal,
            terminal,
            plaintext_returned: false,
            payload_returned_to_support: false,
            path_returned: false,
            key_material_exposed: false,
            next_action: match state {
                ProductionManualEnvelopeOutboundState::ReadyToExport => "export_envelope",
                ProductionManualEnvelopeOutboundState::Exported => "share_outside_app_then_import",
                ProductionManualEnvelopeOutboundState::WaitingForReply => {
                    "wait_for_reply_or_cancel"
                }
                ProductionManualEnvelopeOutboundState::DuplicateImport => "ignore_duplicate_import",
                ProductionManualEnvelopeOutboundState::StaleOrReplayedImport => {
                    "ignore_stale_or_replayed_import"
                }
                ProductionManualEnvelopeOutboundState::Canceled => "write_new_message",
            },
        }
    }

    pub fn production_message_delivery_productization_summary(
        input: ProductionMessageDeliveryProductizationInput,
    ) -> ProductionMessageDeliveryProductizationSummary {
        let current_input_owned = input.current_room_owns_state && input.current_profile_owns_state;
        let recovery_ready =
            input.retry_available && input.cancel_available && input.local_delete_available;
        let fail_closed = input.duplicate_or_replay_rejected && input.peer_mismatch_blocks_verified;
        let support_private_fields_allowed = false;
        let first_message_round_trip_ready = input.profile_unlocked
            && input.pairwise_invite_ready
            && input.mandatory_safety_verified
            && input.compose_ready
            && input.outbound_exported
            && input.inbound_imported
            && input.reply_ready
            && current_input_owned
            && fail_closed
            && input.support_redacted;
        let primary_action = if !current_input_owned {
            ProductionMessageDeliveryPrimaryAction::DeleteOrRebuild
        } else if !input.profile_unlocked {
            ProductionMessageDeliveryPrimaryAction::UnlockProfile
        } else if !input.pairwise_invite_ready {
            ProductionMessageDeliveryPrimaryAction::CreateOrJoinRoom
        } else if !input.mandatory_safety_verified || !input.peer_mismatch_blocks_verified {
            ProductionMessageDeliveryPrimaryAction::VerifySafety
        } else if !input.compose_ready {
            ProductionMessageDeliveryPrimaryAction::WriteMessage
        } else if !input.outbound_exported {
            ProductionMessageDeliveryPrimaryAction::ExportEnvelope
        } else if !input.inbound_imported {
            ProductionMessageDeliveryPrimaryAction::ImportReply
        } else if !input.reply_ready || !input.duplicate_or_replay_rejected || !recovery_ready {
            ProductionMessageDeliveryPrimaryAction::ReplyOrRecover
        } else {
            ProductionMessageDeliveryPrimaryAction::DeleteOrRebuild
        };

        ProductionMessageDeliveryProductizationSummary {
            primary_action,
            first_message_round_trip_ready,
            recovery_ready,
            current_input_owned,
            profile_unlocked: input.profile_unlocked,
            pairwise_invite_ready: input.pairwise_invite_ready,
            mandatory_safety_verified: input.mandatory_safety_verified,
            compose_ready: input.compose_ready,
            outbound_exported: input.outbound_exported,
            inbound_imported: input.inbound_imported,
            reply_ready: input.reply_ready,
            retry_available: input.retry_available,
            cancel_available: input.cancel_available,
            local_delete_available: input.local_delete_available,
            duplicate_or_replay_rejected: input.duplicate_or_replay_rejected,
            peer_mismatch_blocks_verified: input.peer_mismatch_blocks_verified,
            support_redacted: input.support_redacted,
            false_delivered_allowed: false,
            false_verified_allowed: false,
            false_ready_allowed: false,
            message_body_in_support: false,
            envelope_payload_in_support: false,
            invite_body_in_support: false,
            local_path_in_support: false,
            key_or_passphrase_in_support: false,
            support_private_fields_allowed,
            boundary_closed: current_input_owned
                && fail_closed
                && input.support_redacted
                && !support_private_fields_allowed,
        }
    }

