        #[test]
        fn production_product_unlock_status_snapshot_is_redacted_and_portable() {
            let locked =
                production_product_unlock_locked_status_snapshot("wrong-passphrase", 60, 1_000);
            assert!(!locked.unlocked());
            assert_eq!(locked.profile(), "");
            assert_eq!(locked.redacted_reason(), "wrong-passphrase");
            assert!(locked.unlock_command_enabled());
            assert!(!locked.lock_command_enabled());
            assert!(locked.passphrase_first());
            assert!(locked.os_keystore_only_rejected());
            assert!(!locked.storage_opened());
            assert!(!locked.store_path_returned());
            assert!(!locked.passphrase_retained());
            assert!(!locked.key_material_exposed());
            assert!(!locked.raw_storage_error_exposed());
            assert!(!locked.path_or_identifier_exposed());
            assert!(!locked.runtime_messaging_enabled());
            assert!(!locked.rollback_prevention_claimed());
            assert!(!locked.secure_deletion_from_media_claimed());

            let unlocked = production_product_unlock_unlocked_status_snapshot(
                "alice".to_string(),
                "status",
                2_000,
                2_100,
                62_000,
                60,
                2_200,
            );
            assert!(unlocked.unlocked());
            assert_eq!(unlocked.profile(), "alice");
            assert_eq!(unlocked.redacted_reason(), "status");
            assert!(unlocked.lock_command_enabled());
            assert_eq!(unlocked.unlocked_at_ms(), Some(2_000));
            assert_eq!(unlocked.last_activity_ms(), Some(2_100));
            assert_eq!(unlocked.expires_at_ms(), Some(62_000));
            assert_eq!(unlocked.checked_at_ms(), 2_200);
            assert!(!unlocked.passphrase_retained());
            assert!(!unlocked.key_material_exposed());
            assert!(!unlocked.store_path_returned());
            assert!(!unlocked.runtime_messaging_enabled());

            let blocked = production_product_unlock_key_policy_snapshot(
                "rollback-suspicion-blocks-runtime-actions",
                false,
                true,
                true,
                true,
                false,
                false,
            )
            .apply_to_status(unlocked);
            assert!(blocked.rollback_marker_present());
            assert!(blocked.rollback_detection_ready());
            assert!(blocked.rollback_suspicion_detected());
            assert!(blocked.rollback_resume_blocked());
            assert!(!blocked.rollback_prevention_claimed());
            assert!(!blocked.secure_deletion_from_media_claimed());
            assert!(!blocked.key_material_exposed());

            let no_markers = production_product_unlock_key_policy_snapshot_from_markers(
                false, false, false, false, false, false,
            );
            assert_eq!(
                no_markers.key_policy_status(),
                "passphrase-first-runtime-unlock-rollback-marker-unavailable"
            );
            assert!(!no_markers.rollback_marker_present());
            assert!(!no_markers.rollback_detection_ready());
            assert!(!no_markers.rollback_suspicion_detected());
            assert!(!no_markers.rollback_resume_blocked());

            let prepared = production_product_unlock_key_policy_snapshot_from_markers(
                true, true, true, true, true, false,
            );
            assert_eq!(
                prepared.key_policy_status(),
                "passphrase-first-runtime-unlock-with-marker-based-rollback-detection"
            );
            assert!(prepared.passphrase_first_unlock_required());
            assert!(prepared.os_keystore_only_unlock_rejected());
            assert!(!prepared.rollback_suspicion_detected());
            assert!(!prepared.rollback_resume_blocked());

            let partial_marker_family = production_product_unlock_key_policy_snapshot_from_markers(
                true, false, true, true, true, false,
            );
            assert_eq!(
                partial_marker_family.key_policy_status(),
                "rollback-suspicion-blocks-runtime-actions"
            );
            assert!(partial_marker_family.rollback_suspicion_detected());
            assert!(partial_marker_family.rollback_resume_blocked());
            assert!(!partial_marker_family.rollback_prevention_claimed());
            assert!(!partial_marker_family.secure_deletion_from_media_claimed());

            let explicit_suspicion = production_product_unlock_key_policy_snapshot_from_markers(
                true, true, true, true, true, true,
            );
            assert_eq!(
                explicit_suspicion.key_policy_status(),
                "rollback-suspicion-blocks-runtime-actions"
            );
            assert!(explicit_suspicion.rollback_suspicion_detected());
            assert!(explicit_suspicion.rollback_resume_blocked());
        }

        #[test]
        fn production_profile_unlock_recovery_decision_keeps_high_risk_local_claims_explicit() {
            let cases = [
                (
                    ProfileStoreUnlockFailureKind::WrongPassphrase,
                    ProductionProfileUnlockRecoveryKind::WrongPassphrase,
                    true,
                    false,
                    false,
                    "retry-passphrase",
                ),
                (
                    ProfileStoreUnlockFailureKind::MissingStore,
                    ProductionProfileUnlockRecoveryKind::MissingStore,
                    false,
                    true,
                    false,
                    "create-new-local-profile",
                ),
                (
                    ProfileStoreUnlockFailureKind::CorruptStore,
                    ProductionProfileUnlockRecoveryKind::CorruptStore,
                    false,
                    true,
                    false,
                    "inspect-local-store-or-create-new-profile",
                ),
                (
                    ProfileStoreUnlockFailureKind::MigrationNeeded,
                    ProductionProfileUnlockRecoveryKind::MigrationNeeded,
                    false,
                    false,
                    true,
                    "run-supported-local-store-migration",
                ),
                (
                    ProfileStoreUnlockFailureKind::UnsupportedUnlockFactor,
                    ProductionProfileUnlockRecoveryKind::UnsupportedUnlockFactor,
                    true,
                    false,
                    false,
                    "unlock-with-profile-passphrase",
                ),
            ];

            for (
                storage_kind,
                expected_kind,
                retry_with_passphrase_allowed,
                create_new_profile_allowed,
                migration_required,
                next_action,
            ) in cases
            {
                let decision = production_profile_unlock_recovery_decision(storage_kind.into());
                assert_eq!(decision.kind(), expected_kind);
                assert_eq!(
                    decision.retry_with_passphrase_allowed(),
                    retry_with_passphrase_allowed
                );
                assert_eq!(
                    decision.create_new_profile_allowed(),
                    create_new_profile_allowed
                );
                assert_eq!(decision.migration_required(), migration_required);
                assert_eq!(decision.next_action(), next_action);
                assert!(decision.passphrase_required());
                assert!(!decision.os_keychain_only_supported());
                assert!(!decision.raw_store_path_returned());
                assert!(!decision.passphrase_returned());
                assert!(!decision.key_material_exposed());
                assert!(!decision.backup_recovery_claimed());
                assert!(!decision.rollback_protection_claimed());
                assert!(!decision.secure_media_deletion_claimed());
                assert!(!decision.generic_error());
                assert!(decision.not_protected_device_compromise());
            }
        }

        #[test]
        fn production_local_data_recovery_decision_separates_passphrase_corrupt_and_migration_limits(
        ) {
            let cases = [
                (
                    LocalProfileRecoveryFailureKind::PassphraseLoss,
                    ProductionLocalDataRecoveryKind::PassphraseLoss,
                    false,
                    false,
                    true,
                    "create-new-local-profile",
                ),
                (
                    LocalProfileRecoveryFailureKind::CorruptStore,
                    ProductionLocalDataRecoveryKind::CorruptStore,
                    false,
                    false,
                    true,
                    "inspect-local-store-or-create-new-profile",
                ),
                (
                    LocalProfileRecoveryFailureKind::MigrationFailure,
                    ProductionLocalDataRecoveryKind::MigrationFailure,
                    true,
                    true,
                    false,
                    "retry-supported-local-store-migration",
                ),
            ];

            for (
                storage_kind,
                expected_kind,
                migration_required,
                migration_retry_allowed,
                create_new_profile_allowed,
                next_action,
            ) in cases
            {
                let decision = production_local_data_recovery_decision(storage_kind.into());
                assert_eq!(decision.kind(), expected_kind);
                assert!(decision.encrypted_local_export_only());
                assert!(decision.restore_requires_profile_passphrase());
                assert!(!decision.cloud_backup_or_sync_available());
                assert!(!decision.backup_recovery_claimed());
                assert_eq!(decision.migration_required(), migration_required);
                assert_eq!(decision.migration_retry_allowed(), migration_retry_allowed);
                assert!(!decision.destructive_migration_allowed());
                assert!(!decision.silent_data_loss_allowed());
                assert!(!decision.rollback_prevention_claimed());
                assert!(!decision.secure_media_deletion_claimed());
                assert_eq!(
                    decision.create_new_profile_allowed(),
                    create_new_profile_allowed
                );
                assert_eq!(decision.next_action(), next_action);
            }
        }

